import React from "react";
import { motion } from "framer-motion";

export default function App() {
  return (
    <div className="bg-gradient-to-br from-black via-gray-900 to-black text-white min-h-screen font-sans overflow-x-hidden">
      <Navbar />
      <Hero />
      <Services />
      <Portfolio />
      <Pricing />
      <Contact />
      <Footer />
    </div>
  );
}

function Navbar() {
  return (
    <div className="fixed w-full z-50 backdrop-blur-lg bg-black/30 border-b border-gray-800 flex justify-between items-center px-8 py-4">
      <h1 className="text-2xl font-bold bg-gradient-to-r from-purple-400 to-pink-500 text-transparent bg-clip-text">
        DevCraft
      </h1>
      <div className="space-x-8 hidden md:block text-gray-300">
        <a href="#services" className="hover:text-purple-400">Services</a>
        <a href="#portfolio" className="hover:text-purple-400">Work</a>
        <a href="#pricing" className="hover:text-purple-400">Pricing</a>
        <a href="#contact" className="hover:text-purple-400">Contact</a>
      </div>
    </div>
  );
}

function Hero() {
  return (
    <div className="h-screen flex flex-col justify-center items-center text-center px-6 relative">
      <motion.h1
        initial={{ opacity: 0, y: 80 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 1 }}
        className="text-6xl md:text-7xl font-extrabold leading-tight"
      >
        Future of
        <span className="block bg-gradient-to-r from-purple-400 to-blue-500 text-transparent bg-clip-text">
          Web Experiences
        </span>
      </motion.h1>

      <p className="mt-6 text-gray-400 max-w-xl">
        We design ultra-modern, high-performance websites that convert visitors into clients.
      </p>

      <motion.button
        whileHover={{ scale: 1.1 }}
        className="mt-8 px-8 py-4 bg-gradient-to-r from-purple-500 to-blue-500 rounded-full shadow-lg hover:shadow-purple-500/50"
      >
        Start Your Project
      </motion.button>

      {/* Glow effect */}
      <div className="absolute w-96 h-96 bg-purple-500/20 blur-3xl rounded-full top-20" />
    </div>
  );
}

function Services() {
  const services = [
    "Business Websites",
    "Event Websites",
    "Portfolio Design",
    "E-commerce Stores",
    "Custom Web Apps",
    "UI/UX Design",
  ];

  return (
    <div id="services" className="py-24 px-6">
      <h2 className="text-4xl font-bold text-center mb-14">Services</h2>

      <div className="grid md:grid-cols-3 gap-10">
        {services.map((s, i) => (
          <motion.div
            key={i}
            whileHover={{ scale: 1.05 }}
            className="p-8 bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl hover:border-purple-500 transition"
          >
            <h3 className="text-xl font-semibold">{s}</h3>
          </motion.div>
        ))}
      </div>
    </div>
  );
}

function Portfolio() {
  return (
    <div id="portfolio" className="py-24 px-6 bg-black/40">
      <h2 className="text-4xl font-bold text-center mb-14">Our Work</h2>

      <div className="grid md:grid-cols-3 gap-10">
        {[1, 2, 3].map((i) => (
          <motion.div
            key={i}
            whileHover={{ scale: 1.05 }}
            className="h-56 bg-gradient-to-br from-purple-500/20 to-blue-500/20 rounded-2xl backdrop-blur-lg border border-white/10"
          />
        ))}
      </div>
    </div>
  );
}

function Pricing() {
  const plans = [
    { name: "Starter", price: "₹4,999" },
    { name: "Pro", price: "₹9,999" },
    { name: "Enterprise", price: "₹19,999" },
  ];

  return (
    <div id="pricing" className="py-24 px-6">
      <h2 className="text-4xl font-bold text-center mb-14">Pricing</h2>

      <div className="grid md:grid-cols-3 gap-10">
        {plans.map((plan, i) => (
          <motion.div
            key={i}
            whileHover={{ scale: 1.05 }}
            className="p-8 text-center bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl"
          >
            <h3 className="text-2xl font-semibold">{plan.name}</h3>
            <p className="text-3xl mt-4 font-bold text-purple-400">
              {plan.price}
            </p>
          </motion.div>
        ))}
      </div>
    </div>
  );
}

function Contact() {
  return (
    <div id="contact" className="py-24 px-6 bg-black/40 text-center">
      <h2 className="text-4xl font-bold mb-8">Let's Build Something</h2>

      <div className="flex flex-col items-center gap-4">
        <input
          placeholder="Your Email"
          className="p-4 rounded-xl w-80 bg-white/10 border border-white/20 outline-none"
        />

        <textarea
          placeholder="Your Idea"
          className="p-4 rounded-xl w-80 bg-white/10 border border-white/20 outline-none"
        />

        <motion.button
          whileHover={{ scale: 1.1 }}
          className="px-8 py-4 bg-gradient-to-r from-purple-500 to-blue-500 rounded-full shadow-lg"
        >
          Send Message
        </motion.button>
      </div>
    </div>
  );
}

function Footer() {
  return (
    <div className="text-center py-6 border-t border-white/10 text-gray-400">
      © 2026 DevCraft — Future Web Agency
    </div>
  );
}
